export async function seedRoster(storage: IStorage) {
  // ---- Providers ----
  const existingProviders = await storage.listProviders();
  const providerByInitials = new Map<string, number>();
  if (existingProviders.length === 0) {
    for (const r of ROSTER) {
      const created = await storage.createProvider({
        lastName: r.lastName,
        firstName: r.firstName,
        credentials: r.credentials,
        kind: r.kind,
        primaryPool: r.primaryPool,
        eligiblePools: r.eligiblePools,
        notes: null,
        active: true,
        color: null,
      } as any);
      providerByInitials.set(r.initials, created.id);
    }
  } else {
    // Build initials → id map by matching lastName.
    const lastToIni = new Map<string, string>();
    for (const r of ROSTER) lastToIni.set(r.lastName, r.initials);
    for (const p of existingProviders) {
      const ini = lastToIni.get(p.lastName);
      if (ini) providerByInitials.set(ini, p.id);
    }
  }

  // ---- Shifts ----
  const existingShifts = await storage.listShifts();
  if (existingShifts.length === 0) {
    for (const s of SHIFTS) {
      const pid = providerByInitials.get(s.initials);
      if (!pid) {
        console.warn(`seed: no provider id for initials ${s.initials}`);
        continue;
      }
      await storage.createShift({
        pool: s.pool,
        providerId: pid,
        startAt: s.startAt,
        endAt: s.endAt,
        location: s.location,
        note: s.note,
      } as any);
    }
  }

  // ---- Default admin user ----
  const users = await storage.listUsers();
  if (users.length === 0) {
    await storage.createUser({
      username: "admin",
      password: "admin",
      name: "Practice Admin",
      role: "admin",
      providerId: null,
    } as any);
  }
}
